package com.mengwei.localgrowth.platform;
import com.mengwei.localgrowth.identity.AuthService;import java.util.*;import org.springframework.web.bind.annotation.*;
@RestController @RequestMapping("/api/v1/merchants/{merchantId}/platform-assets") public class PlatformAssetController{private final PlatformAssetService s;private final AuthService a;public PlatformAssetController(PlatformAssetService s,AuthService a){this.s=s;this.a=a;}private AuthService.Identity i(String h){return a.verify(h.replaceFirst("Bearer ",""));}@GetMapping public List<Map<String,Object>>profiles(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId){return s.profiles(i(h),merchantId);}@PostMapping public Map<String,Object>create(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId,@RequestBody Map<String,Object>x){return s.createProfile(i(h),merchantId,x);}@GetMapping("/{profileId}")public Map<String,Object>profile(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId,@PathVariable UUID profileId){return s.profile(i(h),merchantId,profileId);}@GetMapping("/{profileId}/fields")public List<Map<String,Object>>fields(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId,@PathVariable UUID profileId){return s.fields(i(h),merchantId,profileId);}@PostMapping("/{profileId}/fields")public Map<String,Object>field(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId,@PathVariable UUID profileId,@RequestBody Map<String,Object>x){return s.addField(i(h),merchantId,profileId,x);}@PostMapping("/{profileId}/compare")public Map<String,Object>compare(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId,@PathVariable UUID profileId){return s.compare(i(h),merchantId,profileId);}@GetMapping("/gaps")public List<Map<String,Object>>gaps(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId){return s.gaps(i(h),merchantId);}@PatchMapping("/gaps/{gapId}")public Map<String,Object>resolve(@RequestHeader("Authorization")String h,@PathVariable UUID merchantId,@PathVariable UUID gapId,@RequestBody Map<String,String>x){return s.resolve(i(h),merchantId,gapId,x.getOrDefault("status","RESOLVED"));}}
